#include <bits/stdc++.h>
#define fr first
#define sc second
using namespace std;
typedef pair<long long,int> pli;

const int N=3e5+10;
const long long INF=1e18;

struct Edge{
    int to,val;
};

int n,sz[N],fa[N],bel[N],f[N],sf[N],p[N][20],cnt[N];
long long dis[N],pf[N],nf[N],g[N][20],s[N],c[N],sum[N];
bool b[N],z[N];
vector<Edge> e[N];
vector<int> v;
vector<pli> vt1,vt2;

void dfs(int x,int lst){
    fa[x]=lst;
    sz[x]=1;
    for(Edge y:e[x])
        if(y.to!=lst && !b[y.to]){
            dfs(y.to,x);
            sz[x]+=sz[y.to];
        }
}

int Balance(int x,int S){
    for(Edge y:e[x])
        if(!b[y.to] && y.to!=fa[x] && sz[y.to]>S/2)
            return Balance(y.to,S);
    return x;
}

void dfs2(int x,long long mindis){
	if(mindis>dis[x])
		z[x]=1,mindis=dis[x];
	else
		z[x]=0;
    v.push_back(x);
    pf[x]=max(pf[fa[x]],dis[x]);
    p[x][0]=fa[x];
    g[x][0]=dis[fa[x]];
    for(int i=1;i<20;i++){
        p[x][i]=p[p[x][i-1]][i-1];
        g[x][i]=max(g[x][i-1],g[p[x][i-1]][i-1]);
    }
    int u=x;
    for(int i=19;i>=0;i--)
        if(g[u][i]<=dis[x])
            u=p[u][i];
    u=fa[u];
    f[x]=f[u]+1;
    if(!u) sf[x]=x;
    else sf[x]=sf[u];
    for(Edge y:e[x])
        if(!b[y.to] && y.to!=fa[x]){
            bel[y.to]=bel[x];
            dis[y.to]=dis[x]+y.val;
            nf[y.to]=max(0ll,nf[x]+y.val);
            dfs2(y.to,mindis);
        }
}

void solve(int x){
    dfs(x,0);
    x=Balance(x,sz[x]);
    dfs(x,0);
    bel[x]=x,pf[x]=nf[x]=dis[x]=0,z[x]=0,sf[x]=x,f[x]=0;
    for(int i=0;i<20;i++)
        p[x][i]=0,g[x][i]=g[0][i]=INF;
    f[0]=-1,sf[0]=0;
    v.clear();
    v.push_back(x);
    sum[x]=cnt[x]=0;
    for(Edge y:e[x])
        if(!b[y.to]){
            bel[y.to]=y.to;
            dis[y.to]=y.val;
            nf[y.to]=max(0,y.val);
            sum[y.to]=cnt[y.to]=0;
            dfs2(y.to,0);
        }
    sum[0]=cnt[0]=0;

    vt1.clear(),vt2.clear();
    for(int i:v){
        sum[bel[i]]+=dis[i],sum[0]+=dis[i];
        cnt[bel[i]]++,cnt[0]++;
        vt1.push_back(make_pair(pf[i],i));
        vt2.push_back(make_pair(nf[i]-dis[i],i));
    }
    sort(vt1.begin(),vt1.end());
    sort(vt2.begin(),vt2.end());
	for(int i=vt1.size()-1,j=i;i>=0;i--){
        int u=vt1[i].sc;
        while(j>=0 && pf[u]<=nf[vt2[j].sc]-dis[vt2[j].sc]){
        	int t=vt2[j].sc;
            sum[bel[t]]+=nf[t]-dis[t];
            sum[0]+=nf[t]-dis[t];
            cnt[0]--,cnt[bel[t]]--;
            j--;
        }
        s[u]+=sum[0]-sum[bel[u]]+(cnt[0]-cnt[bel[u]])*pf[u];
    }

    vt1.clear(),vt2.clear();
    for(int i:v){
    	c[i]+=1ll*f[i]*(sz[x]-sz[bel[i]]);
    	vt1.push_back(make_pair(-dis[sf[i]],i));
    	if(z[i])
    		vt2.push_back(make_pair(dis[i],i));
	}
	sort(vt1.begin(),vt1.end());
	sort(vt2.begin(),vt2.end());
	sum[0]=0;
	for(Edge y:e[x])
		if(!b[y.to])
			sum[y.to]=0;
	for(int i=0,j=0;i<vt1.size();i++){
		int u=vt1[i].sc;
		while(j<vt2.size() && vt2[j].fr<vt1[i].fr){
			int t=vt2[j].sc;
			sum[0]+=sz[t],sum[bel[t]]+=sz[t];
			j++;
		}
		c[u]+=sum[0]-sum[bel[u]]; 
	}
    b[x]=1;
    for(Edge y:e[x])
    	if(!b[y.to])
    		solve(y.to);
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<n;i++){
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        e[u].push_back({v,w});
        e[v].push_back({u,w});
    }
    solve(1);
    puts("1");
    for(int i=1;i<=n;i++)
        printf("%lld ",s[i]);
    puts("");
    for(int i=1;i<=n;i++)
    	printf("%lld ",c[i]);
    return 0;
}
